package spoof

import (
	"fmt"
	"net/http"
	"strings"
)

// isUnknownAuthority checks if the error contains "certificate signed by unknown authority".
// This error happens when OpenShift Route starts/changes to use passthrough mode. It takes a little bit time to be synced.
func isUnknownAuthority(err error) bool {
	return err != nil && strings.Contains(err.Error(), "certificate signed by unknown authority")
}

// RetryingRouteInconsistency retries common requests seen when creating a new route
// - 503 to account for Openshift route inconsistency (https://jira.coreos.com/browse/SRVKS-157)
func RouteInconsistencyRetryChecker(resp *Response) (bool, error) {
	if resp.StatusCode == http.StatusServiceUnavailable {
		return true, fmt.Errorf("retrying route inconsistency request: %s", resp)
	}
	return false, nil
}

// EnvoyRouteNotReadyRetryChecker retries HTTP 404 responses generated by istio-envoy
// when no upstream was contacted (empty body). When a VirtualService is created or
// updated, there is a propagation delay before istiod pushes the new route
// configuration to the Envoy data plane via xDS. During this window Envoy returns
// 404 with an empty body and "Server: istio-envoy" header because it has no matching
// route yet. This is transient and resolves once xDS sync completes.
//
// The check requires both "Server: istio-envoy" AND an empty body to avoid masking
// real 404 errors from upstream applications, which almost always include a response body.
func EnvoyRouteNotReadyRetryChecker(resp *Response) (bool, error) {
	if resp.StatusCode == http.StatusNotFound &&
		resp.Header.Get("Server") == "istio-envoy" &&
		len(resp.Body) == 0 {
		return true, fmt.Errorf("retrying envoy route not ready (VirtualService not yet propagated): %s", resp)
	}
	return false, nil
}
